import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import { phongAPI } from '../services/api';

export default function TaoPhong() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ title: '', giaTien: '', soNguoiToiDa: '', diaChi: '', moTa: '', maPhongCha: '' });
  const [submitting, setSubmitting] = useState(false);
  const set = (k, v) => setForm(f => ({...f, [k]: v}));

  const handleSubmit = async e => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await phongAPI.taoPhong({
        title: form.title,
        giaTien: parseFloat(form.giaTien),
        soNguoiToiDa: parseInt(form.soNguoiToiDa),
        diaChi: form.diaChi,
        moTa: form.moTa,
        maPhongCha: form.maPhongCha ? parseInt(form.maPhongCha) : undefined,
      });
      toast.success('Tạo phòng thành công!');
      navigate('/quan-ly-phong');
    } catch (e) { toast.error(e.response?.data?.message || 'Thất bại'); }
    setSubmitting(false);
  };

  return (
    <div className="container page-wrapper">
      <div style={{ maxWidth: 640, margin:'0 auto' }}>
        <div className="card">
          <div className="card-header">🏠 Tạo phòng mới</div>
          <div className="card-body">
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Tên phòng / Tiêu đề *</label>
                <input className="form-control" required value={form.title} onChange={e => set('title', e.target.value)} placeholder="VD: Phòng 101 - Chung cư ABC" />
              </div>
              <div className="grid-2">
                <div className="form-group">
                  <label className="form-label">Giá thuê (đ/tháng) *</label>
                  <input className="form-control" type="number" required value={form.giaTien} onChange={e => set('giaTien', e.target.value)} placeholder="3000000" />
                </div>
                <div className="form-group">
                  <label className="form-label">Số người tối đa *</label>
                  <input className="form-control" type="number" min="1" max="10" required value={form.soNguoiToiDa} onChange={e => set('soNguoiToiDa', e.target.value)} placeholder="3" />
                </div>
              </div>
              <div className="form-group">
                <label className="form-label">Địa chỉ *</label>
                <input className="form-control" required value={form.diaChi} onChange={e => set('diaChi', e.target.value)} placeholder="Địa chỉ phòng" />
              </div>
              <div className="form-group">
                <label className="form-label">Mã phòng cha (nếu là phòng trong căn hộ)</label>
                <input className="form-control" type="number" value={form.maPhongCha} onChange={e => set('maPhongCha', e.target.value)} placeholder="ID căn hộ" />
              </div>
              <div className="form-group">
                <label className="form-label">Mô tả</label>
                <textarea className="form-control" rows={4} value={form.moTa} onChange={e => set('moTa', e.target.value)} placeholder="Tiện nghi, điều kiện, nội thất..." />
              </div>
              <div style={{ display:'flex', gap:10 }}>
                <button type="submit" className="btn btn-primary btn-lg" style={{ flex:1 }} disabled={submitting}>
                  {submitting ? '⏳...' : '✅ Tạo phòng'}
                </button>
                <button type="button" className="btn btn-secondary btn-lg" onClick={() => navigate(-1)}>Hủy</button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}
